scwin.onpageload = function () {};

/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = async function () {
  let codeOptions = [{
    grpCd: "OP239",
    compID: "gr_master:inspClsCd",
    useLocalCache: false
  }, {
    grpCd: "OP101",
    compID: "gr_master:cntrSizCd",
    useLocalCache: false
  }, {
    grpCd: "OP102",
    compID: "gr_master:cntrTypCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
  await scwin.submitExcute(sbm_lobran);
};

/**
 * @event 
 * @name ondataload 
 * @description 코드 완료
 */
scwin.ondataload = function () {
  scwin.globalVars();
  scwin.f_OnLoad();
};

/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {
  scwin.loginDTO = $c.data.getMemInfo($p);
  scwin.compnoShuttleRate = DsConstants.CMPND_SHUTTLE_RATE; //매출입항목코드(구내셔틀료)
  scwin.shuttleCheck = false;
  scwin.dt = $c.date.getServerDateTime($p, 'yyyyMMdd');
};

/**
 * @method 
 * @name f_OnLoad 
 * @description 페이지로드
 */
scwin.f_OnLoad = async function () {
  ed_stDt.setValue(scwin.dt.slice(0, 6) + '01');
  ed_endDt.setValue(scwin.dt);
  acb_lobran.setValue(scwin.loginDTO.loUpperLobranCd);
  scwin.f_getWrkPlInfo(); //해당점소의 작업장 가져오기;
  acb_wrkPlCd.addItem('전체', '', '', '');
  acb_lobran.focus();

  // test data
  // acb_lobran.setValue('6AA')
  // ed_stDt.setValue('20200101');
  // ed_endDt.setValue('20200110');
};

/**
 * @method 
 * @name f_Retrieve 
 * @description 조회 버튼 클릭시
 */
scwin.f_Retrieve = async function () {
  if (acb_lobran.getValue() == "" || acb_wrkPlCd.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    return;
  }
  ;
  let mmh = ed_mrn.getValue() + ed_msn.getValue() + ed_hsn.getValue();
  let fromDate = ed_stDt.getValue();
  let toDate = ed_endDt.getValue();
  if (fromDate.trim() != "" && toDate.trim() == "" || fromDate.trim() == "" && toDate.trim() != "") {
    if (fromDate.trim() == "") {
      await $c.win.alert($p, "검사 시작일자를 입력하십시오");
      ed_stDt.focus();
      return;
    }
    ;
    if (toDate.trim() == "") {
      await $c.win.alert($p, "검사 종료일자를 입력하십시오");
      ed_endDt.focus();
      return;
    }
    ;
    if (fromDate.trim() > toDate.trim()) {
      await $c.win.alert($p, "조회시작일이 조회종료일보다 큽니다");
      return;
    }
    ;
  }
  ;
  if (fromDate.trim() + toDate.trim() == "") {
    if (ed_blNo.getValue() + ed_cntrNo.getValue() + mmh == "") {
      await $c.win.alert($p, "BL번호/컨테이너번호/화물관리번호 중 한가지는 반드시 입력하십시오");
      ed_blNo.focus();
      return;
    }
    ;
    if (mmh != "") {
      let alertArray = [{
        comp: ed_mrn,
        part: 'MRN'
      }, {
        comp: ed_msn,
        part: 'MSN'
      }, {
        comp: ed_hsn,
        part: 'HSN'
      }];
      alertArray.forEach(async item => {
        if (item.comp.getValue() == "") {
          await $c.win.alert($p, item.part + "을 입력하십시오");
          item.comp.focus();
          return;
        }
        ;
      });
    }
    ;
  }
  ;
  dma_search.undo();
  dma_search.setJSON({
    'branCd': acb_lobran.getValue(),
    //점소
    'wrkPlCd': acb_wrkPlCd.getValue(),
    // 작업장
    'blNo': ed_blNo.getValue(),
    //BL번호
    'cntrNo': ed_cntrNo.getValue(),
    // 컨테이너번호
    'mrn': ed_mrn.getValue(),
    //적하목록관리번호
    'msn': ed_msn.getValue().trim() == "" ? 0 : ed_msn.getValue(),
    //msn
    'hsn': ed_hsn.getValue().trim() == "" ? 0 : ed_hsn.getValue(),
    //hsn
    'stDt': fromDate,
    'endDt': toDate,
    'selpchItemCd': acb_selpchItemCd.getValue()
  });

  //hidden value  setting;
  scwin.h_wrkPlCd = acb_wrkPlCd.getValue();
  scwin.h_blNo = ed_blNo.getValue();
  scwin.h_mrn = ed_mrn.getValue();
  scwin.h_msn = ed_msn.getValue();
  scwin.h_hsn = ed_hsn.getValue();
  scwin.submitExcute(sbm_ret);
};

