/**
 * @method 
 * @name f_Check 
 * @description 저장시 유효성검사
 */
scwin.f_Check = async function () {
  let shuttleRate = 0,
    yardCgshfRate = 0;
  let rowCnt = ds_master.getRowCount();
  let targetData = ds_UnitySelling.getRowJSON(0);
  for (let i = 0; i < rowCnt; i++) {
    let rowData = ds_master.getRowJSON(i);
    ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);
    ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);
    ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);
    if (ds_master.getRowStatusValue(i) == 2) {
      ds_master.setCellData(i, "sellItemCd", rowData.inspClsCd == "01" ? "0028" : "0160");
    }
    ;
    if (rowData.inspDt == "") {
      await $c.win.alert($p, "검사일자를 입력하십시오");
      gr_master.setFocusedCell(i, "inspDt");
      return false;
    }
    ;
    if (rowData.inspClsCd == "") {
      await $c.win.alert($p, "검사구분를 입력하십시오");
      gr_master.setFocusedCell(i, "inspClsCd");
      return false;
    }
    ;
    if (rowData.cntrNo == "") {
      await $c.win.alert($p, "컨테이너 정보를 조회하십시오");
      gr_master.setFocusedCell(i, "cntrNo");
      return false;
    }
    ;
    if (rowData.cmpndCgshfYn != 0) {
      if (rowData.pchsClntNm == "") {
        await $c.win.alert($p, i + "번째 자료가 구내이적되었으나, 매입거래처가 입력되지 않았습니다\n매입거래처를 입력하십시오");
        return false;
      }
      ;
    }
    ;
    if (rowData.cmpndCgshfYn == 0) {
      if (rowData.pchsClntNm != "") {
        await $c.win.alert($p, i + "번째 자료가 매입거래처가 입력되었으나, 구내이적이 선택되지 않았습니다\n구내이적여부를 선택하십시오");
        return false;
      }
      ;
    }
    ;
    if (ds_master.getRowStatusValue(i) == 2 && rowData.chk == 0) {
      if (rowData.lineCd == "") {
        await $c.win.alert($p, "LINE을 입력하십시오");
        gr_master.setFocusedCell(i, "lineCd");
        return false;
      }
      ;
      if (rowData.vsslCd == "") {
        await $c.win.alert($p, "선박코드를 입력하십시오");
        gr_master.setFocusedCell(i, "vsslCd");
        return false;
      }
      ;
      if (rowData.portCd == "") {
        await $c.win.alert($p, "항구코드를 입력하십시오");
        gr_master.setFocusedCell(i, "portCd");
        return false;
      }
      ;
      if (rowData.portcnt == "") {
        await $c.win.alert($p, "항차를 입력하십시오");
        gr_master.setFocusedCell(i, "portcnt");
        return false;
      }
      ;
      ds_master.setCellData(i, "fullEmptyClsCd", "F");
    }
    ;
    if (rowData.inspClsCd == "02") {
      //식물검사 선택시
      if ([1, 2].includes(ds_master.getRowStatusValue(i))) {
        //insert, update 인 경우
        scwin.shuttleCheck = true;
        scwin.f_retrieveSendOutInspectionSelling(i, "cbm"); // 등록되어 있는 구내 셔틀료를 가져온다. 

        shuttleRate = rowData.cmpndShuttleRate; // 입력한 구내셔틀료

        //구내셔틀료는  0원이거나 TB_LO410에 등록한 값이여야한다. (20이면 27,600원, 40이면 39,460) - 2012.08.24
        if (shuttleRate != targetData["comnTrf1"]) {
          if (shuttleRate != 0) {
            await $c.win.alert($p, "구내셔틀료을(를) 잘못 입력 하셨습니다.");
            return false;
          }
          ;
        }
        ;
        if (rowData.wrkPlCd == "6C01") {
          scwin.f_retrieveSendOutInspectionSelling(i, "cbm");
          yardCgshfRate = rowData.yardCgshfRate; // 입력한 장치장이적료

          if (targetData["sellItemCd"] == "0002" && yardCgshfRate != targetData["comnTrf1"] && yardCgshfRate != 0) {
            await $c.win.alert($p, "장치장이적료(를) 잘못 입력 하셨습니다.");
            return false;
          }
          ;
        }
        ;
      }
      ;
    }
    ;
    if (![0, 3].includes(ds_master.getRowStatusValue(i))) {
      //노멀 / 삭제가 아닌 경우;
      if (rowData.newSealNo == "") {
        await $c.win.alert($p, "변경 봉인번호를 입력하십시오");
        gr_master.setFocusedCell(i, "newSealNo");
        return false;
      }
      ;
    }
    ;
    if (rowData.arrvlportDtm == "") {
      ds_master.setCellData(i, "arrvlportDtm", scwin.dt);
    }
    ;
  }
  ;
  return true;
};

