/**
 * @method 
 * @name f_containerInfo 
 * @description 컨테이너 번호를 입력 후, 해당 컨테이너 정보를 조회한다
 * @param {number} row
 * @param {string} cntrNo
 */
scwin.f_containerInfo = async function (row, cntrNo) {
  if (cntrNo == "") return;
  ds_master.setCellData(row, "chk", 0);
  let rowData = ds_master.getRowJSON(row);
  let data = {
    'cntrNo': cntrNo,
    'blNo': ed_blNo.getValue(),
    'IO': ["01", "02"].includes(rowData.inspClsCd) ? 'I' : 'O',
    'wrkPlCd': scwin.h_wrkPlCd.slice(1, 2) == "C" ? scwin.h_wrkPlCd : '',
    'mrn': ed_mrn.getValue(),
    'msn': ed_msn.getValue() == "" ? 0 : ed_msn.getValue(),
    'hsn': ed_hsn.getValue() == "" ? 0 : ed_hsn.getValue()
  };
  let options = {
    'type': 'browserPopup',
    'width': '1210px',
    'height': '486px',
    'popupName': '컨테이너정보조회'
  };
  let url = '/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_38p.xml';
  let ret = await $c.win.openPopup($p, url, options, data);
  if (ret == null || ret[0] == 'N/A' || ret[0] == '') {
    rowData.commCd = "";
    rowData.vsslCd = "";
    rowData.shpCoClntNo = "";
    rowData.portcnt = "";
    rowData.portCd = "";
    rowData.lineCd = "";
    rowData.line = "";
    rowData.mrn = "";
    rowData.msn = "";
    rowData.hsn = "";
    rowData.blNo = "";
    rowData.arrvlportDtm = "";
    rowData.exstSealNo = "";
    rowData.sfe = "";
    ds_master.setRowJSON(row, rowData, true);
  } else {
    if (ret[6] == "") {
      await $c.win.alert($p, "라인거래처정보가 없어 세관검사등록을 할 수 없습니다");
      rowData.cntrNo = "";
      return;
    }
    ;
    rowData.cntrNo = ret[0];
    rowData.cntrSizCd = ret[1];
    rowData.cntrTypCd = ret[2];
    rowData.fullEmptyClsCd = "F"; //ret[3];
    rowData.commCd = ret[4];
    rowData.vsslCd = ret[5];
    rowData.shpCoClntNo = ret[6];
    rowData.portcnt = ret[7];
    rowData.portCd = ret[8];
    rowData.lineCd = ret[9];
    rowData.line = ret[9];
    rowData.mrn = ret[10];
    rowData.msn = ret[11];
    rowData.hsn = ret[12];
    rowData.blNo = ret[13];
    rowData.arrvlportDtm = ret[14];
    rowData.exstSealNo = ret[15];
    rowData.bookingNo = ret[16];
    rowData.sfe = ret[1] + ret[3];
    rowData.chk = 1; //팝업을 통해서 컨테이너를 조회한 경우;

    ds_master.setRowJSON(row, rowData, true);
    scwin.f_retrieveSendOutInspectionSelling(row, "cbm");
  }
  ;
};

