/**
 * @method 
 * @name f_retrievePopUp
 * @description line정보를 조회한다
 * @param {number} row
 * @param {string} colid
 */
scwin.f_retrievePopUp = function (row, colid, pCode) {
  let pSelectId = '',
    pName = '';
  let pClose = 'T',
    pAllSearch = 'T',
    pWtitleSearch = null;

  // LINE
  switch (colid) {
    case "lineCd":
      pSelectId = 'retrieveLineInfoList';
      pName = '';
      pWtitleSearch = 'LINE,LINE코드,LINE명';
      break;
    case "vsslCd":
      pSelectId = 'retrieveVsslCdInfo';
      pName = '';
      pWtitleSearch = '선박,선박코드,선박명';
      break;
    case "portCd":
      pSelectId = 'retrievePortInfo';
      pName = '';
      pWtitleSearch = '항구,항구코드,항구명';
      break;
    case "bilgClntNo":
      pSelectId = 'retrieveClntInfo';
      pName = '';
      pWtitleSearch = '청구처,청구처코드,청구처';
      break;
  }
  ;
  udc_gridComCode.setSelectId(pSelectId);
  udc_gridComCode.cfCommonPopUp(async rtnList => {
    switch (colid) {
      case "lineCd":
        if (rtnList != null && rtnList[0] != "N/A") {
          if (rtnList[2] != "") {
            ds_master.setCellData(row, "lineCd", rtnList[0]);
            ds_master.setCellData(row, "lineNm", rtnList[1]);
            ds_master.setCellData(row, "shpCoClntNo", rtnList[2]);
          } else {
            await $c.win.alert($p, "해당 Line코드는 라인거래처 정보가 없어, 세관검사 등록을 할수 없습니다");
            ds_master.setCellData(row, "lineCd", "");
            ds_master.setCellData(row, "lineNm", "");
            ds_master.setCellData(row, "shpCoClntNo", "");
            return;
          }
        } else {
          ds_master.setCellData(row, "lineCd", "");
          ds_master.setCellData(row, "lineNm", "");
          ds_master.setCellData(row, "shpCoClntNo", "");
        }
        break;
      case "vsslCd":
        if (rtnList != null && rtnList[0] != "N/A") {
          ds_master.setCellData(row, "vsslCd", rtnList[0]);
        } else {
          ds_master.setCellData(row, "vsslCd", "");
        }
        break;
      case "portCd":
        if (rtnList != null && rtnList[0] != "N/A") {
          ds_master.setCellData(row, "portCd", rtnList[0]);
        } else {
          ds_master.setCellData(row, "portCd", "");
        }
        ;
        break;
      case "bilgClntNo":
        if (rtnList != null && rtnList[0] != "N/A") {
          ds_master.setCellData(row, "bilgClntNo", rtnList[0]);
        } else {
          ds_master.setCellData(row, "bilgClntNo", "");
        }
        break;
    }
    ;
  }, pCode, pName,
  // 화면에서의 ??? Name Element의	Value
  pClose,
  // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  null,
  // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  null,
  // Title순서	
  null,
  // 보여주는 각 컬럼들의 폭	
  null,
  // 컬럼중에서 숨기는	컬럼 지정	
  null,
  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  null,
  // POP-UP뛰을때 원도우의	사용자 정의	폭
  null,
  // POP-UP뛰을때 우도우의	사용자 정의	높이	
  null,
  // 윈도우 위치 Y좌표	
  null,
  // 윈도우 위치 X좌표
  null,
  // 중복체크여부	("F")
  pAllSearch,
  // 전체검색허용여부	("F")
  pWtitleSearch // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  );
};

/**
 * @method 
 * @name upperFlag 
 * @description 소문자 입력 시 대문자로 변경
 */
scwin.upperFlag = function (e) {
  this.setValue(e.target.value.toUpperCase());
};

//-----------------------------------------------------------------------------
//   Submission event  
//-----------------------------------------------------------------------------

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_ret:
      // for="tr_ret" event="OnFail()"
      if (e.responseJSON.resultDataSet[0].Code == -1) {
        dma_search.setEmptyValue();
        ds_master.removeAll();
        return;
      }
      ;

      // for="ds_master" event="OnLoadCompleted(rowCnt)"
      let rowCnt = ds_master.getRowCount();
      if (rowCnt == 0) {
        $c.gus.cfAlertMsg($p, "[세관검사등록] " + MSG_CM_ERR_003);
      }
      ;
      gr_master.setColumnReadOnly("cntrNo", false);
      gr_master.setColumnReadOnly("inspDt", true);
      gr_master.setColumnReadOnly("inspClsCd", true);
      totalRows.setValue(rowCnt);
      gr_master.setFocusedCell(0, 'inspDt');
      break;
    case sbm_ret2:
      // for="tr_ret2" event="OnFail()"
      if (e.responseJSON.resultDataSet[0].Code == -1) {
        let focusIdx = ds_master.getRowPosition() ?? 0;
        dma_search2.setEmptyValue();
        ds_master.setCellData(focusIdx, "cbm", 0);
        ds_master.setCellData(focusIdx, "inspAmt", 0);
        ds_master.setCellData(focusIdx, "extrAmt", 0);
        ds_master.setCellData(focusIdx, "totAmt", 0);
        return;
      }
      ;

      // for="ds_UnitySelling" event="OnLoadCompleted(rowCnt)"
      if (ds_UnitySelling.getRowCount() == 0) {
        await $c.win.alert($p, "통합매출 기본정보가 없습니다");
        return;
      }
      ;
      let focusIdx = ds_master.getRowPosition();
      let rowData = ds_master.getRowJSON(focusIdx);
      let targetData = ds_UnitySelling.getRowJSON(0);
      rowData.rsltsStdDt = targetData["rsltsStdDt"];
      rowData.onWrkPlCd = targetData["onWrkPlCd"];
      rowData.sellUpr = targetData["sellUpr"];
      rowData.sellAmt = targetData["sellAmt"];
      rowData.sellAmtFcrc = targetData["sellAmtFcrc"];
      rowData.crcCd = targetData["crcCd"];
      rowData.sellUnitCd = targetData["sellUnitCd"];
      rowData.unitClsCd = targetData["unitClsCd"];
      rowData.sellGoodsPatternCd = targetData["sellGoodsPatternCd"];
      rowData.prebilgYn = targetData["prebilgYn"];
      rowData.dcScCd = targetData["dcScCd"];
      rowData.unsettledCloseYn = targetData["unsettledCloseYn"];
      rowData.bilgTrgtYn = targetData["bilgTrgtYn"];
      rowData.sellYn = targetData["sellYn"];
      rowData.delYn = targetData["delYn"];

      /* 감사료는 = 매출금액(?) */
      if (rowData.inspClsCd == "02") {
        //식물검사 선택시
        if (targetData["sellItemCd"] == scwin.compnoShuttleRate) {
          if (!scwin.shuttleCheck) {
            rowData.cmpndShuttleRate = targetData["comnTrf1"];
          }
        } else if (rowData.wrkPlCd != "6C01") {
          rowData.inspAmt = targetData["sellAmt"];
        }
        ;
        if (rowData.wrkPlCd == "6C01" && targetData["sellItemCd"] == "0002") {
          rowData.yardCgshfRate = targetData["comnTrf1"];
        }
        ;
      } else {
        rowData.inspAmt = targetData["sellAmt"];
      }
      ;
      rowData.totAmt = rowData.extrAmt ?? 0 + rowData.cmpndShuttleRate ?? 0 + rowData.yardCgshfRate ?? 0;
      rowData.cmpndShuttleRate = targetData["comnTrf1"];

      // 변경된 행 데이터를 덮어씌운다
      ds_master.setRowJSON(focusIdx, rowData, true);
      break;

    // 저장
    case sbm_save:
      // for=tr_save event=OnFail()
      if (e.responseJSON.resultDataSet[0].Code == -1) return;

      // for=tr_save event=OnSuccess()
      $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
      scwin.shuttleCheck = false;
      scwin.f_Retrieve();
      break;

    // 점소 콤보 조회
    case sbm_lobran:
      // for="co_ds_lobran" event="OnLoadCompleted(rowCnt)"
      if (ds_lobran_item.getRowCount() == 0) {
        await $c.gus.cfAlertMsg($p, "점소 자료 조회에 실패하였습니다");
        return;
      }
      ;
      break;
    default:
      break;
  }
};

